css:
.print-format { padding: 0.2in; font-size: 10px; }
.transaction-log-title { text-align: center; margin-bottom: 18px; }
.transaction-log-title h2 { margin: 0; font-size: 20px; letter-spacing: 0; }
.transaction-log-meta { width: 100%; margin-bottom: 14px; }
.transaction-log-meta td { padding: 3px 6px; }
.transaction-log-section { margin-top: 14px; font-size: 14px; font-weight: 700; }
.transaction-log-table { width: 100%; border-collapse: collapse; margin-bottom: 10px; table-layout: fixed; }
.transaction-log-table th, .transaction-log-table td { border: 1px solid #d1d8dd; padding: 4px 5px; vertical-align: top; word-wrap: break-word; }
.transaction-log-table th { background: #f4f5f6; font-weight: 700; }
.transaction-log-table .right { text-align: right; }
.transaction-log-table .center { text-align: center; }
.transaction-log-total td { font-weight: 700; }
@media print { .transaction-log-table { page-break-inside: auto; } .transaction-log-table tr { page-break-inside: avoid; page-break-after: auto; } }

html:
{% macro money(value) -%}
{{ frappe.format(value or 0, {"fieldtype": "Currency"}) }}
{%- endmacro %}
{% macro count_rows(rows, series) -%}
{%- set ns = namespace(count=0) -%}
{%- for row in rows -%}{%- if row.series == series -%}{%- set ns.count = ns.count + 1 -%}{%- endif -%}{%- endfor -%}{{ ns.count }}
{%- endmacro %}
{% macro total(rows, series, fieldname) -%}
{%- set ns = namespace(total=0) -%}
{%- for row in rows -%}{%- if row.series == series -%}{%- set ns.total = ns.total + (row.get(fieldname) or 0) -%}{%- endif -%}{%- endfor -%}{{ money(ns.total) }}
{%- endmacro %}
{% macro cancelled_table(rows) -%}
<h3 class="transaction-log-section">Cancelled Pawn Tickets</h3>
<table class="transaction-log-table">
<thead><tr><th>Date Loan Granted</th><th>Pawn Ticket</th><th>Principal</th><th>Net Proceeds</th><th>Status</th></tr></thead>
<tbody>
{% for row in rows %}<tr><td>{{ row.get_formatted("transaction_date") }}</td><td>{{ row.pawn_ticket or "" }}</td><td class="right">{{ money(row.principal) }}</td><td class="right">{{ money(row.net_proceeds) }}</td><td>{{ row.status or "" }}</td></tr>{% endfor %}
</tbody></table>
{%- endmacro %}
{% macro new_sangla_table(rows, series, label) -%}
<table class="transaction-log-table">
<thead><tr><th>Date Loan Granted</th><th>Pawn Ticket ({{ label }})</th><th>Inventory#</th><th>Principal</th><th>Net Proceeds</th></tr></thead>
<tbody>
{% for row in rows %}{% if row.series == series %}<tr><td>{{ row.get_formatted("transaction_date") }}</td><td>{{ row.pawn_ticket or "" }}</td><td>{{ row.inventory_no or "" }}</td><td class="right">{{ money(row.principal) }}</td><td class="right">{{ money(row.net_proceeds) }}</td></tr>{% endif %}{% endfor %}
<tr class="transaction-log-total"><td>Count: {{ count_rows(rows, series) }}</td><td></td><td class="right">Total:</td><td class="right">{{ total(rows, series, "principal") }}</td><td class="right">{{ total(rows, series, "net_proceeds") }}</td></tr>
</tbody></table>
{%- endmacro %}
{% macro redeemed_table(rows, series, label) -%}
<table class="transaction-log-table">
<thead><tr><th>Date Redeemed</th><th>Inventory#</th><th>Pawn Ticket ({{ label }})</th><th>Principal</th><th>Net Proceeds</th><th>Accrued Interest</th><th>Short Term Discount</th><th>Other Discount</th></tr></thead>
<tbody>
{% for row in rows %}{% if row.series == series %}<tr><td>{{ row.get_formatted("transaction_date") }}</td><td>{{ row.inventory_no or "" }}</td><td>{{ row.pawn_ticket or "" }}</td><td class="right">{{ money(row.principal) }}</td><td class="right">{{ money(row.net_proceeds) }}</td><td class="right">{{ money(row.accrued_interest) }}</td><td class="right">{{ money(row.short_term_discount) }}</td><td class="right">{{ money(row.other_discount) }}</td></tr>{% endif %}{% endfor %}
<tr class="transaction-log-total"><td>Count: {{ count_rows(rows, series) }}</td><td></td><td class="right">Total:</td><td class="right">{{ total(rows, series, "principal") }}</td><td class="right">{{ total(rows, series, "net_proceeds") }}</td><td class="right">{{ total(rows, series, "accrued_interest") }}</td><td class="right">{{ total(rows, series, "short_term_discount") }}</td><td class="right">{{ total(rows, series, "other_discount") }}</td></tr>
</tbody></table>
{%- endmacro %}
{% macro renewed_table(rows, series, label) -%}
<table class="transaction-log-table">
<thead><tr><th>Date Renewed</th><th>Inventory#</th><th>Old Pawn Ticket ({{ label }})</th><th>New Pawn Ticket ({{ label }})</th><th>Principal</th><th>Net Proceeds</th><th>Accrued Interest</th><th>Other Discount</th></tr></thead>
<tbody>
{% for row in rows %}{% if row.series == series %}<tr><td>{{ row.get_formatted("transaction_date") }}</td><td>{{ row.inventory_no or "" }}</td><td>{{ row.old_pawn_ticket or row.pawn_ticket or "" }}</td><td>{{ row.new_pawn_ticket or "" }}</td><td class="right">{{ money(row.principal) }}</td><td class="right">{{ money(row.net_proceeds) }}</td><td class="right">{{ money(row.accrued_interest) }}</td><td class="right">{{ money(row.other_discount) }}</td></tr>{% endif %}{% endfor %}
<tr class="transaction-log-total"><td>Count: {{ count_rows(rows, series) }}</td><td></td><td></td><td class="right">Total:</td><td class="right">{{ total(rows, series, "principal") }}</td><td class="right">{{ total(rows, series, "net_proceeds") }}</td><td class="right">{{ total(rows, series, "accrued_interest") }}</td><td class="right">{{ total(rows, series, "other_discount") }}</td></tr>
</tbody></table>
{%- endmacro %}
{% macro renewed_amortization_table(rows, series, label) -%}
<table class="transaction-log-table">
<thead><tr><th>Date Renewed</th><th>Inventory#</th><th>Old Pawn Ticket ({{ label }})</th><th>New Pawn Ticket ({{ label }})</th><th>Old Principal</th><th>Amortization Amount</th><th>New Principal</th><th>New Net Proceeds</th><th>Accrued Interest</th><th>Other Discount</th></tr></thead>
<tbody>
{% for row in rows %}{% if row.series == series %}<tr><td>{{ row.get_formatted("transaction_date") }}</td><td>{{ row.inventory_no or "" }}</td><td>{{ row.old_pawn_ticket or row.pawn_ticket or "" }}</td><td>{{ row.new_pawn_ticket or "" }}</td><td class="right">{{ money(row.old_principal) }}</td><td class="right">{{ money(row.amortization_amount) }}</td><td class="right">{{ money(row.new_principal) }}</td><td class="right">{{ money(row.old_net_proceeds) }}</td><td class="right">{{ money(row.accrued_interest) }}</td><td class="right">{{ money(row.other_discount) }}</td></tr>{% endif %}{% endfor %}
<tr class="transaction-log-total"><td>Count: {{ count_rows(rows, series) }}</td><td></td><td></td><td class="right">Total:</td><td class="right">{{ total(rows, series, "old_principal") }}</td><td class="right">{{ total(rows, series, "amortization_amount") }}</td><td class="right">{{ total(rows, series, "new_principal") }}</td><td class="right">{{ total(rows, series, "old_net_proceeds") }}</td><td class="right">{{ total(rows, series, "accrued_interest") }}</td><td class="right">{{ total(rows, series, "other_discount") }}</td></tr>
</tbody></table>
{%- endmacro %}
{% macro amortization_table(rows, series, label) -%}
<table class="transaction-log-table">
<thead><tr><th>Date of Amortization</th><th>Pawn Ticket ({{ label }})</th><th>Inventory#</th><th>Amortization Amount</th><th>New Principal</th></tr></thead>
<tbody>
{% for row in rows %}{% if row.series == series %}<tr><td>{{ row.get_formatted("transaction_date") }}</td><td>{{ row.pawn_ticket or "" }}</td><td>{{ row.inventory_no or "" }}</td><td class="right">{{ money(row.amortization_amount) }}</td><td class="right">{{ money(row.new_principal) }}</td></tr>{% endif %}{% endfor %}
<tr class="transaction-log-total"><td></td><td></td><td class="right">Total:</td><td class="right">{{ total(rows, series, "amortization_amount") }}</td><td class="right">{{ total(rows, series, "new_principal") }}</td></tr>
</tbody></table>
{%- endmacro %}
{% macro interest_table(rows, series, label) -%}
<table class="transaction-log-table">
<thead><tr><th>Date of Payment</th><th>Type</th><th>Pawn Ticket({{ label }})</th><th>Partial Interest Paid</th></tr></thead>
<tbody>
{% for row in rows %}{% if row.series == series %}<tr><td>{{ row.get_formatted("transaction_date") }}</td><td>{% if row.pawn_ticket_type == "Pawn Ticket Non Jewelry" %}Gadget{% endif %}</td><td>{{ row.pawn_ticket or "" }}</td><td class="right">{{ money(row.partial_interest_paid) }}</td></tr>{% endif %}{% endfor %}
<tr class="transaction-log-total"><td></td><td></td><td class="right">Total:</td><td class="right">{{ total(rows, series, "partial_interest_paid") }}</td></tr>
</tbody></table>
{%- endmacro %}
<div class="transaction-log-title"><h2>TRANSACTION LOG</h2><div>{{ doc.name }}</div></div>
<table class="transaction-log-meta"><tr><td><b>Date:</b></td><td>{{ doc.get_formatted("date") }}</td><td><b>Branch:</b></td><td>{{ doc.branch }}</td></tr><tr><td></td><td></td><td><b>Cash Position Report:</b></td><td>{{ doc.cash_position_report }}</td></tr></table>
{{ cancelled_table(doc.cancelled_pawn_tickets) }}
<h3 class="transaction-log-section">New Sangla</h3>{{ new_sangla_table(doc.new_sangla, "A", "A") }}{{ new_sangla_table(doc.new_sangla, "B", "B") }}{{ new_sangla_table(doc.new_sangla, "NJ", "NJ") }}
<h3 class="transaction-log-section">Redeemed Pawn Tickets</h3>{{ redeemed_table(doc.redeemed_pawn_tickets, "A", "A") }}{{ redeemed_table(doc.redeemed_pawn_tickets, "B", "B") }}{{ redeemed_table(doc.redeemed_pawn_tickets, "NJ", "NJ") }}
<h3 class="transaction-log-section">Renewed Pawn Tickets</h3>{{ renewed_table(doc.renewed_pawn_tickets, "A", "A") }}{{ renewed_table(doc.renewed_pawn_tickets, "B", "B") }}{{ renewed_table(doc.renewed_pawn_tickets, "NJ", "NJ") }}
<h3 class="transaction-log-section">Renewed Pawn Tickets with Amortization</h3>{{ renewed_amortization_table(doc.renewed_with_amortization, "A", "A") }}{{ renewed_amortization_table(doc.renewed_with_amortization, "B", "B") }}{{ renewed_amortization_table(doc.renewed_with_amortization, "NJ", "NJ") }}
<h3 class="transaction-log-section">Amortizations only</h3>{{ amortization_table(doc.amortizations_only, "A", "A") }}{{ amortization_table(doc.amortizations_only, "B", "B") }}{{ amortization_table(doc.amortizations_only, "NJ", "NJ") }}
<h3 class="transaction-log-section">Interest Payment</h3>{{ interest_table(doc.interest_payments, "A", "A") }}{{ interest_table(doc.interest_payments, "B", "B") }}
<h3 class="transaction-log-section">Summary</h3><table class="transaction-log-table"><thead><tr><th>Description</th><th>Total</th></tr></thead><tbody>{% for row in doc.summary %}<tr><td>{{ row.description }}</td><td class="right">{% if loop.index <= 2 %}{{ (row.total or 0)|int }}{% else %}{{ money(row.total) }}{% endif %}</td></tr>{% endfor %}</tbody></table>
